import { useEffect, useState } from "react";
import axios from "axios";

function Appointments() {
  const [data, setData] = useState([]);

  const user = JSON.parse(localStorage.getItem("user"));

  const fetchData = () => {
    axios.get("http://localhost:5000/api/appointments", {
      params: {
        userId: user?._id,
        role: user?.role,
        name: user?.name
      }
    })
    .then(res => setData(res.data));
  };

  useEffect(() => {
    fetchData();
  }, []);

  // ✅ NEW: Update status
  const handleStatus = async (id, status) => {
    await axios.put(`http://localhost:5000/api/appointments/status/${id}`, {
      status
    });

    fetchData(); // refresh
  };

  return (
    <div className="main">
      <h2>Appointments</h2>

      <div className="cards">
        {data.map(a => (
          <div key={a._id} className="card-box">

            {user?.role === "doctor" ? (
  <p><b>Patient:</b> {a.patientName}</p>
) : (
  <p><b>Doctor:</b> {a.doctorName}</p>
)}
            <p><b>Date:</b> {a.date}</p>
            <p><b>Time:</b> {a.time}</p>

            <p><b>Problem:</b> {a.problem}</p>
            <p><b>Symptoms:</b> {a.symptoms}</p>

            {/* ✅ STATUS */}
            <p>
              <b>Status:</b>{" "}
              <span style={{
                color:
                  a.status === "accepted" ? "green" :
                  a.status === "rejected" ? "red" :
                  "orange"
              }}>
                {a.status}
              </span>
            </p>

            {/* ✅ ONLY DOCTOR CAN SEE BUTTONS */}
            {user?.role === "doctor" && a.status === "pending" && (
              <>
                <button
                  onClick={() => handleStatus(a._id, "accepted")}
                  style={{ background: "green", marginBottom: "5px" }}
                >
                  Accept
                </button>

                <button
                  onClick={() => handleStatus(a._id, "rejected")}
                  style={{ background: "red" }}
                >
                  Reject
                </button>
              </>
            )}

          </div>
        ))}
      </div>
    </div>
  );
}

export default Appointments;
